// Build alert payload from error trigger context
const e = $input.first().json;
const wf = e.workflow || {};
const exec = e.execution || {};
const lastNode = exec.lastNodeExecuted || 'unknown';
const errMsg = (exec.error?.message || JSON.stringify(exec.error || {})).slice(0, 500);

return [{json: {
  kind: 'alert',
  service: `n8n-workflow:${wf.name || wf.id || 'unknown'}`,
  classification: 'workflow_failure',
  severity: 'high',
  summary: `Workflow '${wf.name}' נכשל בצומת '${lastNode}'\n\nשגיאה: ${errMsg}`,
  suggested_fix: `פתח את ההפעלה ב-n8n ובדוק: ${wf.id ? `https://n8n-production-986a.up.railway.app/workflow/${wf.id}/executions/${exec.id}` : 'n8n executions'}`,
  incident_id: `wf_${wf.id || 'x'}_${exec.id || Date.now()}`
}}];
